  1→"use client";
  2→
  3→import { Input } from "@/components/ui/input";
  4→import { Label } from "@/components/ui/label";
  5→import { ScrollArea } from "@/components/ui/scroll-area";
  6→import { Switch } from "@/components/ui/switch";
  7→import { cn } from "@/lib/utils";
  8→import { ChevronDown, ChevronRight } from "lucide-react";
  9→import { memo, useState } from "react";
 10→import {
 11→  CHART_TYPE_LABELS,
 12→  type ChartType,
 13→  type GaugeOptions,
 14→  type PieOptions,
 15→  type StatOptions,
 16→  type TableOptions,
 17→  type TimeseriesOptions,
 18→} from "./use-panel-edit-state";
 19→
 20→// --- Toggle Option Button ---
 21→function ToggleOption({
 22→  selected,
 23→  onClick,
 24→  children,
 25→}: {
 26→  selected: boolean;
 27→  onClick: () => void;
 28→  children: React.ReactNode;
 29→}) {
 30→  return (
 31→    <button
 32→      type="button"
 33→      className={cn(
 34→        "px-2.5 py-1 rounded-md border text-xs transition-colors",
 35→        selected
 36→          ? "bg-primary text-primary-foreground border-primary"
 37→          : "hover:bg-muted/50"
 38→      )}
 39→      onClick={onClick}
 40→    >
 41→      {children}
 42→    </button>
 43→  );
 44→}
 45→
 46→// --- Collapsible Section ---
 47→function Section({
 48→  title,
 49→  children,
 50→  defaultOpen = true,
 51→}: {
 52→  title: string;
 53→  children: React.ReactNode;
 54→  defaultOpen?: boolean;
 55→}) {
 56→  const [open, setOpen] = useState(defaultOpen);
 57→  return (
 58→    <div className="border-b last:border-b-0">
 59→      <button
 60→        type="button"
 61→        className="flex items-center gap-1.5 w-full px-3 py-2 text-xs font-medium text-muted-foreground uppercase tracking-wider hover:bg-muted/30 transition-colors"
 62→        onClick={() => setOpen(!open)}
 63→      >
 64→        {open ? (
 65→          <ChevronDown className="h-3 w-3" />
 66→        ) : (
 67→          <ChevronRight className="h-3 w-3" />
 68→        )}
 69→        {title}
 70→      </button>
 71→      {open && <div className="px-3 pb-3 space-y-3">{children}</div>}
 72→    </div>
 73→  );
 74→}
 75→
 76→// --- Select dropdown ---
 77→function SimpleSelect({
 78→  value,
 79→  options,
 80→  onChange,
 81→}: {
 82→  value: string;
 83→  options: { value: string; label: string }[];
 84→  onChange: (value: string) => void;
 85→}) {
 86→  return (
 87→    <select
 88→      value={value}
 89→      onChange={(e) => onChange(e.target.value)}
 90→      className="w-full h-8 rounded-md border bg-background px-2 text-xs"
 91→    >
 92→      {options.map((opt) => (
 93→        <option key={opt.value} value={opt.value}>
 94→          {opt.label}
 95→        </option>
 96→      ))}
 97→    </select>
 98→  );
 99→}
100→
101→// --- Main Sidebar Props ---
102→interface PanelEditSidebarProps {
103→  title: string;
104→  onTitleChange: (title: string) => void;
105→  chartType: ChartType;
106→  onChartTypeChange: (type: ChartType) => void;
107→  gridW: number;
108→  gridH: number;
109→  onGridSizeChange: (w: number, h: number) => void;
110→  // Type-specific options
111→  statOptions: StatOptions;
112→  onStatOptionsChange: (partial: Partial<StatOptions>) => void;
113→  timeseriesOptions: TimeseriesOptions;
114→  onTimeseriesOptionsChange: (
115→    partial: Partial<TimeseriesOptions>
116→  ) => void;
117→  pieOptions: PieOptions;
118→  onPieOptionsChange: (partial: Partial<PieOptions>) => void;
119→  gaugeOptions: GaugeOptions;
120→  onGaugeOptionsChange: (partial: Partial<GaugeOptions>) => void;
121→  tableOptions: TableOptions;
122→  onTableOptionsChange: (partial: Partial<TableOptions>) => void;
123→}
124→
125→function PanelEditSidebarComponent({
126→  title,
127→  onTitleChange,
128→  chartType,
129→  onChartTypeChange,
130→  gridW,
131→  gridH,
132→  onGridSizeChange,
133→  statOptions,
134→  onStatOptionsChange,
135→  timeseriesOptions,
136→  onTimeseriesOptionsChange,
137→  pieOptions,
138→  onPieOptionsChange,
139→  gaugeOptions,
140→  onGaugeOptionsChange,
141→  tableOptions,
142→  onTableOptionsChange,
143→}: PanelEditSidebarProps) {
144→  const isTitleEmpty = title.trim().length === 0;
145→
146→  return (
147→    <div className="flex flex-col h-full">
148→      {/* Sidebar header */}
149→      <div className="flex items-center px-3 py-1.5 border-b bg-muted/30 shrink-0">
150→        <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
151→          Panel Options
152→        </span>
153→      </div>
154→
155→      <ScrollArea className="flex-1">
156→        <div className="divide-y">
157→          {/* Panel title */}
158→          <Section title="Panel Title">
159→            <div>
160→              <Input
161→                value={title}
162→                onChange={(e) => onTitleChange(e.target.value)}
163→                placeholder="Enter panel name"
164→                className={cn(
165→                  "h-8 text-sm",
166→                  isTitleEmpty && "border-destructive focus-visible:ring-destructive"
167→                )}
168→              />
169→              {isTitleEmpty && (
170→                <p className="text-[11px] text-destructive mt-1">
171→                  Required — Apply is disabled without a name
172→                </p>
173→              )}
174→            </div>
175→          </Section>
176→
177→          {/* Visualization type */}
178→          <Section title="Visualization">
179→            <div className="flex flex-wrap gap-1.5">
180→              {(
181→                Object.entries(CHART_TYPE_LABELS) as [
182→                  ChartType,
183→                  string,
184→                ][]
185→              ).map(([type, label]) => (
186→                <ToggleOption
187→                  key={type}
188→                  selected={chartType === type}
189→                  onClick={() => onChartTypeChange(type)}
190→                >
191→                  {label}
192→                </ToggleOption>
193→              ))}
194→            </div>
195→          </Section>
196→
197→          {/* Type-specific options */}
198→          {chartType === "stat" && (
199→            <StatOptionsSection
200→              options={statOptions}
201→              onChange={onStatOptionsChange}
202→            />
203→          )}
204→          {(chartType === "line" ||
205→            chartType === "bar" ||
206→            chartType === "area") && (
207→            <TimeseriesOptionsSection
208→              chartType={chartType}
209→              options={timeseriesOptions}
210→              onChange={onTimeseriesOptionsChange}
211→            />
212→          )}
213→          {chartType === "pie" && (
214→            <PieOptionsSection
215→              options={pieOptions}
216→              onChange={onPieOptionsChange}
217→            />
218→          )}
219→          {chartType === "gauge" && (
220→            <GaugeOptionsSection
221→              options={gaugeOptions}
222→              onChange={onGaugeOptionsChange}
223→            />
224→          )}
225→          {chartType === "table" && (
226→            <TableOptionsSection
227→              options={tableOptions}
228→              onChange={onTableOptionsChange}
229→            />
230→          )}
231→
232→          {/* Grid size */}
233→          <Section title="Panel Size">
234→            <div className="space-y-2">
235→              <div>
236→                <Label className="text-xs">Width</Label>
237→                <div className="flex flex-wrap gap-1.5 mt-1">
238→                  {[
239→                    { value: 6, label: "Quarter" },
240→                    { value: 8, label: "Third" },
241→                    { value: 12, label: "Half" },
242→                    { value: 16, label: "2/3" },
243→                    { value: 24, label: "Full" },
244→                  ].map((opt) => (
245→                    <ToggleOption
246→                      key={opt.value}
247→                      selected={gridW === opt.value}
248→                      onClick={() =>
249→                        onGridSizeChange(opt.value, gridH)
250→                      }
251→                    >
252→                      {opt.label}
253→                    </ToggleOption>
254→                  ))}
255→                </div>
256→              </div>
257→              <div>
258→                <Label className="text-xs">Height</Label>
259→                <div className="flex flex-wrap gap-1.5 mt-1">
260→                  {[
261→                    { value: 3, label: "Small" },
262→                    { value: 4, label: "Compact" },
263→                    { value: 6, label: "Medium" },
264→                    { value: 8, label: "Large" },
265→                    { value: 10, label: "X-Large" },
266→                    { value: 12, label: "Tall" },
267→                  ].map((opt) => (
268→                    <ToggleOption
269→                      key={opt.value}
270→                      selected={gridH === opt.value}
271→                      onClick={() =>
272→                        onGridSizeChange(gridW, opt.value)
273→                      }
274→                    >
275→                      {opt.label}
276→                    </ToggleOption>
277→                  ))}
278→                </div>
279→              </div>
280→            </div>
281→          </Section>
282→
283→          {/* Template variables reference */}
284→          <Section title="Variable Reference" defaultOpen={false}>
285→            <div className="space-y-1.5 text-[11px]">
286→              <VarRow
287→                name="{timeFilter}"
288→                desc="Time range filter expression"
289→              />
290→              <VarRow
291→                name="{filterExpression}"
292→                desc="Combined filter conditions"
293→              />
294→              <VarRow
295→                name="{from:String}"
296→                desc="Start datetime string"
297→              />
298→              <VarRow
299→                name="{to:String}"
300→                desc="End datetime string"
301→              />
302→              <VarRow
303→                name="{rounding:UInt32}"
304→                desc="Time bucket size in seconds"
305→              />
306→              <VarRow
307→                name="{seconds:UInt32}"
308→                desc="Total time range in seconds"
309→              />
310→            </div>
311→          </Section>
312→        </div>
313→      </ScrollArea>
314→    </div>
315→  );
316→}
317→
318→// --- Variable Reference Row ---
319→function VarRow({ name, desc }: { name: string; desc: string }) {
