211→export function usePanelEditState(editingPanel?: PanelDescriptor | null) {
212→  // Preserved original descriptor for merging non-UI options
213→  const originalDescriptorRef = useRef<PanelDescriptor | null>(
214→    editingPanel ?? null
215→  );
216→
217→  const [chartType, setChartTypeState] = useState<ChartType>(() =>
218→    editingPanel ? (editingPanel.type as ChartType) : "line"
219→  );
220→  const [title, setTitleState] = useState(
221→    () => editingPanel?.titleOption?.title ?? ""
222→  );
223→  const [sql, setSqlState] = useState(
224→    () => editingPanel?.datasource?.sql ?? ""
225→  );
226→  const [gridW, setGridW] = useState(() => editingPanel?.gridPos?.w ?? 12);
227→  const [gridH, setGridH] = useState(() => editingPanel?.gridPos?.h ?? 6);
228→
229→  const [statOptions, setStatOptions] = useState<StatOptions>(() =>
230→    extractStatOptions(editingPanel)
231→  );
232→  const [timeseriesOptions, setTimeseriesOptions] =
233→    useState<TimeseriesOptions>(() =>
234→      extractTimeseriesOptions(editingPanel)
235→    );
236→  const [pieOptions, setPieOptions] = useState<PieOptions>(() =>
237→    extractPieOptions(editingPanel)
238→  );
239→  const [gaugeOptions, setGaugeOptions] = useState<GaugeOptions>(() =>
240→    extractGaugeOptions(editingPanel)
241→  );
242→  const [tableOptions, setTableOptions] = useState<TableOptions>(() =>
243→    extractTableOptions(editingPanel)
244→  );
245→
246→  const [previewDescriptor, setPreviewDescriptor] =
247→    useState<PanelDescriptor | null>(() =>
248→      editingPanel ? buildDescriptorFromState(
249→        editingPanel.type as ChartType,
250→        editingPanel.titleOption?.title ?? "",
251→        editingPanel.datasource?.sql ?? "",
252→        editingPanel.gridPos?.w ?? 12,
253→        editingPanel.gridPos?.h ?? 6,
254→        extractStatOptions(editingPanel),
255→        extractTimeseriesOptions(editingPanel),
256→        extractPieOptions(editingPanel),
257→        extractGaugeOptions(editingPanel),
258→        extractTableOptions(editingPanel),
259→        editingPanel
260→      ) : null
261→    );
262→  const [previewKey, setPreviewKey] = useState(0);
263→  const [isDirty, setIsDirty] = useState(false);
264→
265→  // Track whether a preview has been created (either from editing or from running a query)
266→  const hasPreviewRef = useRef(!!editingPanel);
267→  // Keep a ref to the latest sql so the auto-update effect uses current sql
268→  // without re-firing on every keystroke
269→  const sqlRef = useRef(sql);
270→  sqlRef.current = sql;
271→
272→  const markDirty = useCallback(() => setIsDirty(true), []);
273→
274→  const setTitle = useCallback(
275→    (value: string) => {
276→      setTitleState(value);
277→      markDirty();
278→    },
279→    [markDirty]
280→  );
281→
282→  const setSql = useCallback(
283→    (value: string) => {
284→      setSqlState(value);
285→      markDirty();
286→    },
287→    [markDirty]
288→  );
289→
290→  const setChartType = useCallback(
291→    (type: ChartType) => {
292→      setChartTypeState(type);
293→      markDirty();
294→    },
295→    [markDirty]
296→  );
297→
298→  const setGridSize = useCallback(
299→    (w: number, h: number) => {
300→      setGridW(w);
301→      setGridH(h);
302→      markDirty();
303→    },
304→    [markDirty]
305→  );
306→
307→  const updateStatOptions = useCallback(
308→    (partial: Partial<StatOptions>) => {
309→      setStatOptions((prev) => ({ ...prev, ...partial }));
310→      markDirty();
311→    },
312→    [markDirty]
313→  );
314→
315→  const updateTimeseriesOptions = useCallback(
316→    (partial: Partial<TimeseriesOptions>) => {
317→      setTimeseriesOptions((prev) => ({ ...prev, ...partial }));
318→      markDirty();
319→    },
320→    [markDirty]
321→  );
322→
323→  const updatePieOptions = useCallback(
324→    (partial: Partial<PieOptions>) => {
325→      setPieOptions((prev) => ({ ...prev, ...partial }));
326→      markDirty();
327→    },
328→    [markDirty]
329→  );
330→
331→  const updateGaugeOptions = useCallback(
332→    (partial: Partial<GaugeOptions>) => {
333→      setGaugeOptions((prev) => ({ ...prev, ...partial }));
334→      markDirty();
335→    },
336→    [markDirty]
337→  );
338→
339→  const updateTableOptions = useCallback(
340→    (partial: Partial<TableOptions>) => {
341→      setTableOptions((prev) => ({ ...prev, ...partial }));
342→      markDirty();
343→    },
344→    [markDirty]
345→  );
346→
347→  const runQuery = useCallback(() => {
348→    const descriptor = buildDescriptorFromState(
349→      chartType,
350→      title,
351→      sql,
352→      gridW,
353→      gridH,
354→      statOptions,
355→      timeseriesOptions,
356→      pieOptions,
357→      gaugeOptions,
358→      tableOptions,
359→      originalDescriptorRef.current
360→    );
361→    setPreviewDescriptor(descriptor);
362→    setPreviewKey((k) => k + 1);
363→    hasPreviewRef.current = true;
364→  }, [
365→    chartType,
366→    title,
367→    sql,
368→    gridW,
369→    gridH,
370→    statOptions,
371→    timeseriesOptions,
372→    pieOptions,
373→    gaugeOptions,
374→    tableOptions,
375→  ]);
376→
377→  // Auto-update preview when visual options change (without re-running the query).
378→  // This lets the user see chart type, legend, title, grid size, etc. changes
379→  // reflected immediately. SQL changes still require an explicit "Run Query".
380→  useEffect(() => {
381→    if (!hasPreviewRef.current) return;
382→
383→    const updated = buildDescriptorFromState(
384→      chartType,
385→      title,
386→      sqlRef.current,
387→      gridW,
388→      gridH,
389→      statOptions,
390→      timeseriesOptions,
391→      pieOptions,
392→      gaugeOptions,
393→      tableOptions,
394→      originalDescriptorRef.current
395→    );
396→    setPreviewDescriptor(updated);
397→  }, [
398→    chartType,
399→    title,
400→    gridW,
401→    gridH,
402→    statOptions,
403→    timeseriesOptions,
404→    pieOptions,
405→    gaugeOptions,
406→    tableOptions,
407→  ]);
408→
409→  const buildDescriptor = useCallback((): PanelDescriptor | null => {
410→    if (!title.trim() || !sql.trim()) return null;
411→    return buildDescriptorFromState(
412→      chartType,
413→      title,
414→      sql,
415→      gridW,
416→      gridH,
417→      statOptions,
418→      timeseriesOptions,
419→      pieOptions,
420→      gaugeOptions,
421→      tableOptions,
422→      originalDescriptorRef.current
423→    );
424→  }, [
425→    chartType,
426→    title,
427→    sql,
428→    gridW,
429→    gridH,
430→    statOptions,
431→    timeseriesOptions,
432→    pieOptions,
433→    gaugeOptions,
434→    tableOptions,
435→  ]);
436→
437→  const applyTemplate = useCallback(
438→    (template: WidgetTemplate) => {
439→      setChartTypeState(template.chartType);
440→      setTitleState(template.name);
441→      setSqlState(template.sql);
442→      setGridW(template.gridW);
443→      setGridH(template.gridH);
444→      markDirty();
445→    },
446→    [markDirty]
447→  );
448→
449→  const isValid = title.trim().length > 0 && sql.trim().length > 0;
450→
451→  return {
452→    // State
453→    chartType,
454→    title,
455→    sql,
456→    gridW,
457→    gridH,
458→    statOptions,
459→    timeseriesOptions,
460→    pieOptions,
461→    gaugeOptions,
462→    tableOptions,
463→    previewDescriptor,
464→    previewKey,
465→    isDirty,
466→    isValid,
467→
468→    // Actions
469→    setChartType,
470→    setTitle,
471→    setSql,
472→    setGridSize,
473→    updateStatOptions,
474→    updateTimeseriesOptions,
475→    updatePieOptions,
476→    updateGaugeOptions,
477→    updateTableOptions,
478→    runQuery,
479→    buildDescriptor,
480→    applyTemplate,
481→  };
482→}
483→
484→// --- Helper functions ---
485→
486→function extractStatOptions(
487→  panel?: PanelDescriptor | null
488→): StatOptions {
489→  if (!panel || panel.type !== "stat") return DEFAULT_STAT_OPTIONS;
490→  const d = panel as StatDescriptor;
491→  return {
492→    minimapType: d.minimapOption?.type ?? "area",
493→    reducer: d.valueOption?.reducer ?? "last",
494→    format: d.valueOption?.format ?? "short_number",
495→  };
496→}
497→
498→function extractTimeseriesOptions(
499→  panel?: PanelDescriptor | null
500→): TimeseriesOptions {
501→  if (
502→    !panel ||
503→    (panel.type !== "line" && panel.type !== "bar" && panel.type !== "area")
504→  )
505→    return DEFAULT_TIMESERIES_OPTIONS;
506→  const d = panel as TimeseriesDescriptor;
507→  return {
508→    legendPlacement: d.legendOption?.placement ?? "bottom",
509→    yAxisFormat: d.yAxis?.[0]?.format ?? "short_number",
510→    stacked: d.stacked ?? false,
511→  };
512→}
513→
514→function extractPieOptions(
515→  panel?: PanelDescriptor | null
516→): PieOptions {
517→  if (!panel || panel.type !== "pie") return DEFAULT_PIE_OPTIONS;
518→  const d = panel as PieDescriptor;
519→  return {
520→    legendPlacement: d.legendOption?.placement ?? "right",
521→    labelFormat: d.labelOption?.format ?? "name-percent",
522→  };
523→}
524→
525→function extractGaugeOptions(
526→  panel?: PanelDescriptor | null
527→): GaugeOptions {
528→  if (!panel || panel.type !== "gauge") return DEFAULT_GAUGE_OPTIONS;
529→  const d = panel as GaugeDescriptor;
530→  return {
531→    min: d.gaugeOption?.min ?? 0,
532→    max: d.gaugeOption?.max ?? 100,
533→    valueFormat: d.gaugeOption?.valueFormat ?? "",
534→  };
535→}
536→
537→function extractTableOptions(
538→  panel?: PanelDescriptor | null
539→): TableOptions {
540→  if (!panel || panel.type !== "table") return DEFAULT_TABLE_OPTIONS;
541→  const d = panel as TableDescriptor;
542→  return {
543→    stickyHeader: d.headOption?.isSticky ?? false,
544→    serverSideSorting: d.sortOption?.serverSideSorting ?? false,
545→  };
546→}
547→
548→function buildDescriptorFromState(
549→  chartType: ChartType,
550→  title: string,
551→  sql: string,
552→  gridW: number,
553→  gridH: number,
554→  statOpts: StatOptions,
555→  timeseriesOpts: TimeseriesOptions,
556→  pieOpts: PieOptions,
557→  gaugeOpts: GaugeOptions,
558→  tableOpts: TableOptions,
559→  originalDescriptor?: PanelDescriptor | null
560→): PanelDescriptor {
561→  const gridPos: GridPos = { w: gridW, h: gridH };
562→
563→  const base: PanelDescriptor = {
564→    type: chartType,
565→    titleOption: { title: title.trim() },
566→    gridPos,
567→    datasource: { sql: sql.trim() },
568→  };
569→
570→  // Preserve any fields from the original descriptor that aren't managed by the UI
571→  switch (chartType) {
572→    case "stat": {
573→      const original = originalDescriptor?.type === "stat"
574→        ? (originalDescriptor as StatDescriptor)
575→        : undefined;
576→      return {
577→        ...base,
578→        type: "stat",
579→        minimapOption: { type: statOpts.minimapType },
580→        valueOption: {
581→          ...original?.valueOption,
582→          reducer: statOpts.reducer,
583→          format: statOpts.format as any,
584→        },
585→        comparisonOption: original?.comparisonOption,
586→      } as StatDescriptor;
587→    }
588→    case "line":
589→    case "bar":
590→    case "area": {
591→      const original =
592→        originalDescriptor?.type === chartType
593→          ? (originalDescriptor as TimeseriesDescriptor)
594→          : undefined;
595→      return {
596→        ...base,
597→        type: chartType,
598→        legendOption: { placement: timeseriesOpts.legendPlacement },
599→        yAxis: [
600→          {
601→            ...original?.yAxis?.[0],
602→            format: timeseriesOpts.yAxisFormat as any,
603→          },
604→        ],
605→        tooltipOption: original?.tooltipOption,
606→        stacked: timeseriesOpts.stacked,
607→        fieldOptions: original?.fieldOptions,
608→      } as TimeseriesDescriptor;
609→    }
610→    case "pie": {
611→      const original =
612→        originalDescriptor?.type === "pie"
613→          ? (originalDescriptor as PieDescriptor)
614→          : undefined;
615→      return {
616→        ...base,
617→        type: "pie",
618→        legendOption: { placement: pieOpts.legendPlacement },
619→        labelOption: {
620→          show: true,
621→          format: pieOpts.labelFormat,
622→        },
623→        valueFormat: original?.valueFormat,
624→        fieldOptions: original?.fieldOptions,
625→      } as PieDescriptor;
626→    }
627→    case "gauge": {
628→      const original =
629→        originalDescriptor?.type === "gauge"
630→          ? (originalDescriptor as GaugeDescriptor)
631→          : undefined;
632→      return {
633→        ...base,
634→        type: "gauge",
635→        gaugeOption: {
636→          ...original?.gaugeOption,
637→          min: gaugeOpts.min,
638→          max: gaugeOpts.max,
639→          valueFormat: gaugeOpts.valueFormat as any,
640→        },
641→        fieldOptions: original?.fieldOptions,
642→      } as GaugeDescriptor;
643→    }
644→    case "table": {
645→      const original =
646→        originalDescriptor?.type === "table"
647→          ? (originalDescriptor as TableDescriptor)
648→          : undefined;
649→      return {
650→        ...base,
651→        type: "table",
652→        headOption: { isSticky: tableOpts.stickyHeader },
653→        sortOption: {
654→          ...original?.sortOption,
655→          serverSideSorting: tableOpts.serverSideSorting,
656→        },
657→        fieldOptions: original?.fieldOptions,
658→        pagination: original?.pagination,
659→        miscOption: original?.miscOption,
660→        actions: original?.actions,
661→      } as TableDescriptor;
662→    }
663→    default:
664→      return base;
665→  }
666→}
